eight:700;color:#6d28d9;line-height:1;margin-bottom:8px}\n.mex-prf-stat-label{font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:400;color:rgba(255,255,255,0.85);margin-top:0}\n.mex-prf-text{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.8;max-width:700px;margin:0 auto;padding:0}\n\n.et_pb_section .mex-prf-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .mex-prf-text{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n.et_pb_section .mex-prf-stat-value{-webkit-font-smoothing:auto !important;line-height:1 !important;margin-bottom:8px !important}\n.et_pb_section .mex-prf-stat-label{-webkit-font-smoothing:auto !important;line-height:22.4px !important;margin-top:0 !important}\n.et_pb_section .mex-prf-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .mex-prf-stat{-webkit-font-smoothing:auto !important}\n.et_pb_section .mex-prf-stats-bar{margin-bottom:40px !important}\n\n@media(max-width:768px){\n  .mex-prf-stats-bar{grid-template-columns:repeat(2,1fr);gap:24px}\n  .mex-prf-stat:not(:last-child){border-right:none}\n  .mex-prf-stat:nth-child(odd){border-right:1px solid rgba(255,255,255,0.1)}\n  .mex-prf-title{font-size:28px}\n  .mex-prf-stat-value{font-size:32px}\n}\n@media(max-width:480px){\n  .mex-prf-stats-bar{grid-template-columns:1fr}\n  .mex-prf-stat:nth-child(odd){border-right:none}\n}\n@media(prefers-reduced-motion:reduce){.mex-prf-section *{transition:none !important}}\n/* === LOGISTICS === */\n.mex-log-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.mex-log-inner{max-width:900px;margin:0 auto}\n.mex-log-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#6d28d9;margin-bottom: